from math import gcd

n = int(input())
a = [int(x) for x in input().split()]
g = [[] for _ in range(n)]
for i in range(n):
    for j in range(i + 1, n):
        if gcd(a[i], a[j]) > 1:
            g[i].append(j)
            g[j].append(i)


def dfs(i, seen):
    ans = 1
    seen[i] = 1
    for j in g[i]:
        if not seen[j]:
            ans += dfs(j, seen)
    return ans


ans = 0
seen = [0] * n
for i in range(n):
    if not seen[i]:
        ans = max(ans, dfs(i, seen))
print(ans)
